import type { IdentifierString } from "@wallet-standard/base";

/**
 * Chain identifier for Rialo Development Network.
 * Used for active development and testing new features.
 */
export const RIALO_DEVNET_CHAIN = "rialo:devnet";

/**
 * Chain identifier for Rialo Testnet.
 * Used for integration testing with test tokens.
 */
export const RIALO_TESTNET_CHAIN = "rialo:testnet";

/**
 * Chain identifier for Rialo Local Network.
 * Used for local development with a local validator.
 */
export const RIALO_LOCALNET_CHAIN = "rialo:localnet";

/**
 * Array of all supported Rialo chain identifiers.
 * Used for validation and iteration over available chains.
 */
export const RIALO_CHAINS = [
  RIALO_DEVNET_CHAIN,
  RIALO_TESTNET_CHAIN,
  RIALO_LOCALNET_CHAIN,
] as const;

/**
 * Union type of all supported Rialo chain identifiers.
 * Use this type when accepting or returning chain identifiers.
 *
 * @example
 * ```typescript
 * function connectToChain(chain: RialoChain): void {
 *   // TypeScript ensures only valid chains are passed
 * }
 * ```
 */
export type RialoChain = (typeof RIALO_CHAINS)[number];

/**
 * Type guard to check if a string is a valid Rialo chain identifier.
 *
 * @param chain - The chain identifier to validate.
 * @returns True if the chain is a valid Rialo chain, false otherwise.
 *
 * @example
 * ```typescript
 * const chain: IdentifierString = "rialo:devnet";
 * if (isRialoChain(chain)) {
 *   // chain is narrowed to RialoChain type
 *   console.log("Valid Rialo chain:", chain);
 * }
 * ```
 */
export function isRialoChain(chain: IdentifierString): chain is RialoChain {
  return RIALO_CHAINS.includes(chain as RialoChain);
}
