import type {
  RialoSignAndSendTransactionInput,
  RialoSignAndSendTransactionOutput,
} from "./signAndSendTransaction";

/**
 * Feature identifier for the Rialo sign and send all transactions capability.
 * Use this constant to access the signAndSendAllTransactions feature from a wallet.
 *
 * @example
 * ```typescript
 * const results = await wallet.features[RialoSignAndSendAllTransactions].signAndSendAllTransactions(
 *   [
 *     { account, transaction: tx1Bytes, chain: "rialo:devnet" },
 *     { account, transaction: tx2Bytes, chain: "rialo:devnet" }
 *   ],
 *   { mode: "serial" }
 * );
 *
 * for (const result of results) {
 *   if (result.status === "fulfilled") {
 *     console.log("Success:", result.value.signature);
 *   } else {
 *     console.error("Failed:", result.reason);
 *   }
 * }
 * ```
 */
export const RialoSignAndSendAllTransactions = "rialo:signAndSendAllTransactions";

/**
 * Feature definition for signing and sending multiple transactions atomically.
 * Useful for batch operations where all transactions should be submitted together.
 * Returns PromiseSettledResult to handle partial failures gracefully.
 */
export type RialoSignAndSendAllTransactionsFeature = {
  readonly [RialoSignAndSendAllTransactions]: {
    /** Version of the signAndSendAllTransactions feature implementation. */
    readonly version: RialoSignAndSendAllTransactionsVersion;

    /** Method to sign and send multiple transactions. */
    readonly signAndSendAllTransactions: RialoSignAndSendAllTransactionsMethod;
  };
};

/** Current version of the signAndSendAllTransactions feature. */
export type RialoSignAndSendAllTransactionsVersion = "1.0.0";

/**
 * Method signature for signing and sending multiple transactions.
 * Unlike signAndSendTransaction, this takes an array of inputs (not rest params)
 * and returns PromiseSettledResult to handle partial failures.
 *
 * @param inputs - Array of transaction signing and sending requests.
 * @param options - Optional configuration for batch processing.
 * @returns Promise resolving to an array of settled results (fulfilled or rejected).
 */
export type RialoSignAndSendAllTransactionsMethod = (
  inputs: readonly RialoSignAndSendTransactionInput[],
  options?: RialoSignAndSendAllTransactionsOptions
) => Promise<readonly PromiseSettledResult<RialoSignAndSendTransactionOutput>[]>;

/**
 * Options for batch transaction processing.
 */
export type RialoSignAndSendAllTransactionsOptions = {
  /**
   * Execution mode for the batch of transactions.
   * - "parallel": Submit all transactions concurrently (faster, but order not guaranteed).
   * - "serial": Submit transactions one at a time in order (slower, but ordered).
   */
  readonly mode?: RialoSignAndSendAllTransactionsMode;
};

/**
 * Execution mode for batch transaction processing.
 */
export type RialoSignAndSendAllTransactionsMode = "parallel" | "serial";
