import type { IdentifierString } from "@wallet-standard/base";
import type { RialoSignTransactionInput } from "./signTransaction";

/**
 * Feature identifier for the Rialo sign and send transaction capability.
 * Use this constant to access the signAndSendTransaction feature from a wallet.
 *
 * @example
 * ```typescript
 * const result = await wallet.features[RialoSignAndSendTransaction].signAndSendTransaction({
 *   account,
 *   transaction: transactionBytes,
 *   chain: "rialo:devnet"
 * });
 * console.log("Transaction signature:", result.signature);
 * ```
 */
export const RialoSignAndSendTransaction = "rialo:signAndSendTransaction";

/**
 * Feature definition for signing and immediately submitting a transaction.
 * This is the most common flow for single transaction operations.
 */
export type RialoSignAndSendTransactionFeature = {
  readonly [RialoSignAndSendTransaction]: {
    /** Version of the signAndSendTransaction feature implementation. */
    readonly version: RialoSignAndSendTransactionVersion;

    /** Method to sign and send one or more transactions. */
    readonly signAndSendTransaction: RialoSignAndSendTransactionMethod;
  };
};

/** Current version of the signAndSendTransaction feature. */
export type RialoSignAndSendTransactionVersion = "1.0.0";

/**
 * Method signature for signing and sending transactions.
 * Accepts multiple inputs and returns corresponding outputs.
 *
 * @param inputs - One or more transaction signing and sending requests.
 * @returns Promise resolving to an array of transaction signatures.
 */
export type RialoSignAndSendTransactionMethod = (
  ...inputs: readonly RialoSignAndSendTransactionInput[]
) => Promise<readonly RialoSignAndSendTransactionOutput[]>;

/**
 * Input parameters for signing and sending a transaction.
 * Extends RialoSignTransactionInput but requires chain to be specified.
 */
export interface RialoSignAndSendTransactionInput extends RialoSignTransactionInput {
  /**
   * The chain to submit the transaction to.
   * Required for signAndSendTransaction to know which network to use.
   */
  readonly chain: IdentifierString;
}

/**
 * Output from a sign and send transaction operation.
 */
export interface RialoSignAndSendTransactionOutput {
  /** The transaction signature returned by the network. */
  readonly signature: Uint8Array;
}
