import type { WalletAccount } from "@wallet-standard/base";
import { RialoSignAndSendAllTransactions } from "./features/signAndSendAllTransactions";
import { RialoSignAndSendTransaction } from "./features/signAndSendTransaction";
import { RialoSignMessage } from "./features/signMessage";
import { RialoSignTransaction } from "./features/signTransaction";
import { RIALO_CHAINS } from "./rialo";

/** Supported chains for all Rialo wallet accounts. */
const chains: WalletAccount["chains"] = RIALO_CHAINS;

/** Features supported by all Rialo wallet accounts. */
const features = [
  RialoSignTransaction,
  RialoSignAndSendTransaction,
  RialoSignAndSendAllTransactions,
  RialoSignMessage,
] as const;

/**
 * Implementation of the WalletAccount interface for Rialo wallets.
 *
 * This class represents a connected account in a Rialo wallet, providing
 * access to the account's address, public key, supported chains, and features.
 *
 * The class is immutable - all properties are readonly and the instance is
 * frozen upon construction to prevent modification.
 *
 * @example
 * ```typescript
 * const account = new RialoWalletAccount({
 *   address: "rialo1abc...",
 *   publicKey: new Uint8Array([...]),
 *   label: "My Wallet",
 *   icon: "data:image/svg+xml;base64,..."
 * });
 *
 * console.log(account.address); // "rialo1abc..."
 * console.log(account.chains);  // ["rialo:devnet", "rialo:testnet", "rialo:localnet"]
 * ```
 */
export class RialoWalletAccount implements WalletAccount {
  readonly #address: WalletAccount["address"];
  readonly #publicKey: WalletAccount["publicKey"];
  readonly #chains: WalletAccount["chains"];
  readonly #features: WalletAccount["features"];
  readonly #label: WalletAccount["label"];
  readonly #icon: WalletAccount["icon"];

  /**
   * The address of this account.
   * This is the human-readable identifier for the account on the Rialo network.
   */
  public get address(): WalletAccount["address"] {
    return this.#address;
  }

  /**
   * The public key of this account.
   * Returns a copy to prevent external modification.
   */
  public get publicKey(): WalletAccount["publicKey"] {
    return this.#publicKey.slice();
  }

  /**
   * The chains this account supports.
   * Returns a copy to prevent external modification.
   */
  public get chains(): WalletAccount["chains"] {
    return this.#chains.slice();
  }

  /**
   * The features this account supports.
   * Returns a copy to prevent external modification.
   */
  public get features(): WalletAccount["features"] {
    return this.#features.slice();
  }

  /**
   * Optional human-readable label for this account.
   * May be displayed in wallet UIs to help users identify accounts.
   */
  public get label(): WalletAccount["label"] {
    return this.#label;
  }

  /**
   * Optional icon for this account as a data URL.
   * May be displayed in wallet UIs alongside the account.
   */
  public get icon(): WalletAccount["icon"] {
    return this.#icon;
  }

  /**
   * Creates a new RialoWalletAccount instance.
   *
   * The account is automatically configured with all supported Rialo chains
   * and features. The instance is frozen to ensure immutability.
   *
   * @param params - Account initialization parameters.
   * @param params.address - The account's address on the Rialo network.
   * @param params.publicKey - The account's Ed25519 public key as bytes.
   * @param params.label - Optional human-readable label for the account.
   * @param params.icon - Optional icon as a data URL (e.g., "data:image/svg+xml;base64,...").
   */
  public constructor({
    address,
    publicKey,
    label,
    icon,
  }: Omit<WalletAccount, "chains" | "features">) {
    if (new.target === RialoWalletAccount) {
      Object.freeze(this);
    }

    this.#address = address;
    this.#publicKey = publicKey;
    this.#chains = chains;
    this.#features = features;
    this.#label = label;
    this.#icon = icon;
  }
}
