import type { IdentifierString, WalletAccount } from "@wallet-standard/base";

/**
 * Feature identifier for the Rialo sign transaction capability.
 * Use this constant to access the signTransaction feature from a wallet.
 *
 * @example
 * ```typescript
 * const result = await wallet.features[RialoSignTransaction].signTransaction({
 *   account,
 *   transaction: transactionBytes,
 *   chain: "rialo:devnet"
 * });
 * ```
 */
export const RialoSignTransaction = "rialo:signTransaction";

/**
 * Feature definition for signing transactions without submitting them.
 * Use this when you need to sign a transaction but submit it separately,
 * or when collecting multiple signatures.
 */
export type RialoSignTransactionFeature = {
  readonly [RialoSignTransaction]: {
    /** Version of the signTransaction feature implementation. */
    readonly version: RialoSignTransactionVersion;

    /** Method to sign one or more transactions. */
    readonly signTransaction: RialoSignTransactionMethod;
  };
};

/** Current version of the signTransaction feature. */
export type RialoSignTransactionVersion = "1.0.0";

/**
 * Method signature for signing transactions.
 * Accepts multiple inputs and returns corresponding outputs.
 *
 * @param inputs - One or more transaction signing requests.
 * @returns Promise resolving to an array of signed transaction outputs.
 */
export type RialoSignTransactionMethod = (
  ...inputs: readonly RialoSignTransactionInput[]
) => Promise<readonly RialoSignTransactionOutput[]>;

/**
 * Input parameters for signing a transaction.
 */
export interface RialoSignTransactionInput {
  /** The account to use for signing. */
  readonly account: WalletAccount;

  /** The serialized transaction bytes to sign. */
  readonly transaction: Uint8Array;

  /**
   * The chain to sign for (e.g., "rialo:devnet", "rialo:testnet").
   * Optional - wallet may use its current chain if not specified.
   */
  readonly chain?: IdentifierString;
}

/**
 * Output from a transaction signing operation.
 */
export interface RialoSignTransactionOutput {
  /** The fully signed transaction bytes, ready for submission. */
  readonly signedTransaction: Uint8Array;
}
