import type { WalletAccount } from "@wallet-standard/base";

/**
 * Feature identifier for the Rialo sign message capability.
 * Use this constant to access the signMessage feature from a wallet.
 *
 * @example
 * ```typescript
 * const result = await wallet.features[RialoSignMessage].signMessage({
 *   account,
 *   message: new TextEncoder().encode("Hello, Rialo!")
 * });
 * ```
 */
export const RialoSignMessage = "rialo:signMessage";

/**
 * Feature definition for signing arbitrary messages with a Rialo wallet.
 * Implements the wallet-standard feature pattern for message signing.
 */
export type RialoSignMessageFeature = {
  readonly [RialoSignMessage]: {
    /** Version of the signMessage feature implementation. */
    readonly version: RialoSignMessageVersion;

    /** Method to sign one or more messages. */
    readonly signMessage: RialoSignMessageMethod;
  };
};

/** Current version of the signMessage feature. */
export type RialoSignMessageVersion = "1.0.0";

/**
 * Method signature for signing messages.
 * Accepts multiple inputs and returns corresponding outputs.
 *
 * @param inputs - One or more message signing requests.
 * @returns Promise resolving to an array of signed message outputs.
 */
export type RialoSignMessageMethod = (
  ...inputs: readonly RialoSignMessageInput[]
) => Promise<readonly RialoSignMessageOutput[]>;

/**
 * Input parameters for signing a message.
 */
export interface RialoSignMessageInput {
  /** The account to use for signing. */
  readonly account: WalletAccount;

  /** The message bytes to sign. */
  readonly message: Uint8Array;
}

/**
 * Output from a message signing operation.
 */
export interface RialoSignMessageOutput {
  /** The original message that was signed. */
  readonly signedMessage: Uint8Array;

  /** The Ed25519 signature of the message. */
  readonly signature: Uint8Array;

  /** The signature algorithm used. Always "ed25519" for Rialo. */
  readonly signatureType?: "ed25519";
}
