import type { WalletIcon } from "@wallet-standard/base";

/**
 * Default icon for Rialo wallet as a base64-encoded SVG data URL.
 * This icon can be used to display the Rialo wallet branding in wallet UIs.
 *
 * @example
 * ```typescript
 * import { icon } from "@rialo/wallet-standard";
 *
 * // Use in an img element
 * <img src={icon} alt="Rialo Wallet" />
 * ```
 */
export const icon: WalletIcon =
  "data:image/svg+xml;base64," as const;
